select resource_id, report_id, resource_type, resource_url, resource_sort
from shop_verification_report_resource where report_id = #{reportId}
order by resource_sort, resource_id

select feed.* from ( select 'TRIAL' as content_type, c.campaign_id as content_id, p.product_id, p.merchant_id, m.company_name as merchant_name, pc.category_code, pc.category_name, c.campaign_title as title, c.campaign_summary as summary, p.cover_url, c.published_at, (p.stock > 0) as purchasable, c.target_count, c.trial_type, (select count(1) from shop_trial_application a where a.campaign_id = c.campaign_id and a.status in ('APPROVED', 'SHIPPED', 'RECEIVED', 'COMPLETED')) as approved_count, c.application_deadline, null as report_user_id, null as report_user_name, null as report_shortcoming, null as report_recommend, null as report_ai_score, null as report_ai_score_status from shop_trial_campaign c inner join shop_product p on p.product_id = c.product_id and p.del_flag = '0' inner join shop_merchant m on m.merchant_id = p.merchant_id and m.del_flag = '0' inner join shop_product_category pc on pc.category_id = p.category_id where c.status = 'RECRUITING' and c.application_deadline > sysdate() and (select count(1) from shop_trial_application active_application where active_application.campaign_id = c.campaign_id and active_application.status in ('APPROVED', 'SHIPPED', 'RECEIVED', 'COMPLETED')) < c.target_count and m.audit_status = 'APPROVED' and m.status = '0' and p.status = 'ON_SALE' and pc.status = '0' union all select 'REPORT' as content_type, r.report_id as content_id, p.product_id, p.merchant_id, m.company_name as merchant_name, pc.category_code, pc.category_name, p.product_name as title, substring(r.experience, 1, 180) as summary, coalesce((select rr.resource_url from shop_verification_report_resource rr where rr.report_id = r.report_id order by rr.resource_sort, rr.resource_id limit 1), p.cover_url) as cover_url, r.published_at, (p.stock > 0) as purchasable, null as target_count, null as trial_type, null as approved_count, null as application_deadline, r.shop_user_id as report_user_id, coalesce(u.nick_name, u.user_name) as report_user_name, r.shortcoming as report_shortcoming, r.recommend as report_recommend, r.ai_score as report_ai_score, r.ai_score_status as report_ai_score_status from shop_verification_report r inner join shop_product p on p.product_id = r.product_id and p.del_flag = '0' inner join shop_merchant m on m.merchant_id = p.merchant_id and m.del_flag = '0' inner join shop_product_category pc on pc.category_id = p.category_id inner join shop_user u on u.user_id = r.shop_user_id and u.del_flag = '0' where r.status = 'PUBLISHED' and m.audit_status = 'APPROVED' and m.status = '0' and p.status = 'ON_SALE' and pc.status = '0' ) feed
feed.category_code = #{categoryCode}
and feed.content_type = #{contentType}
and feed.content_type = 'TRIAL' and feed.trial_type = #{trialType}
order by feed.published_at desc, feed.content_id desc
